"use client"

import * as React from "react"

import { prefersReducedMotion } from "../lib/df-dnd"
import {
  DEFAULT_COLUMNS,
  cellDeltaFromPointer,
  cellMetricsFromGridRect,
  layoutById,
  layoutEquals,
  moveWidget,
  normalizeLayout,
  resizeWidget,
  translateFromCellDelta,
  type WidgetGridCellMetrics,
  type WidgetLayoutItem,
} from "../lib/df-widget-grid"
import { cn } from "../lib/utils"

const DRAG_HANDLE_SELECTOR = "[data-df-widget-drag-handle]"
const DEFAULT_ROW_HEIGHT_PX = 80
const DEFAULT_GAP_PX = 16

export type WidgetGridProps = Omit<
  React.HTMLAttributes<HTMLDivElement>,
  "children"
> & {
  layout: WidgetLayoutItem[]
  onLayoutChange?: (layout: WidgetLayoutItem[]) => void
  renderWidget: (id: string) => React.ReactNode
  columns?: number
  /** When false, drag, resize, and keyboard edit affordances are disabled. */
  editable?: boolean
  /**
   * Override `--df-widget-grid-row-height` for this instance.
   * Accepts a CSS length such as `5rem` or `80px`.
   */
  minRowHeight?: string
  emptyContent?: React.ReactNode
}

type GestureKind = "move" | "resize-se" | "resize-e" | "resize-s"

type PointerSession = {
  pointerId: number
  kind: GestureKind
  id: string
  origin: WidgetLayoutItem
  startClientX: number
  startClientY: number
  metrics: WidgetGridCellMetrics
}

type GesturePreview = {
  id: string
  kind: GestureKind
  draft: WidgetLayoutItem
  translateX: number
  translateY: number
  scaleX: number
  scaleY: number
}

type KeyboardDraft = {
  id: string
  originLayout: WidgetLayoutItem[]
  draftLayout: WidgetLayoutItem[]
}

function readCssPx(token: string, fallback: number): number {
  if (typeof document === "undefined") return fallback
  const raw = getComputedStyle(document.documentElement)
    .getPropertyValue(token)
    .trim()
  const px = Number.parseFloat(raw)
  return Number.isFinite(px) && px > 0 ? px : fallback
}

function readElementPx(
  element: HTMLElement,
  token: string,
  fallback: number
): number {
  const raw = getComputedStyle(element).getPropertyValue(token).trim()
  const px = Number.parseFloat(raw)
  return Number.isFinite(px) && px > 0 ? px : fallback
}

function captureGridMetrics(
  root: HTMLElement,
  columns: number
): WidgetGridCellMetrics {
  const rect = root.getBoundingClientRect()
  const styles = getComputedStyle(root)
  const gapX =
    Number.parseFloat(styles.columnGap || styles.gap) ||
    readElementPx(root, "--df-widget-grid-gap", DEFAULT_GAP_PX)
  const gapY =
    Number.parseFloat(styles.rowGap || styles.gap) ||
    readElementPx(root, "--df-widget-grid-gap", DEFAULT_GAP_PX)
  const rowHeight = readElementPx(
    root,
    "--df-widget-grid-row-height",
    readCssPx("--df-widget-grid-row-height", DEFAULT_ROW_HEIGHT_PX)
  )
  return cellMetricsFromGridRect({
    width: rect.width,
    columns,
    rowHeight,
    gapX: Number.isFinite(gapX) ? gapX : DEFAULT_GAP_PX,
    gapY: Number.isFinite(gapY) ? gapY : DEFAULT_GAP_PX,
  })
}

function formatWidgetCell(item: WidgetLayoutItem): string {
  return `column ${item.x + 1}, row ${item.y + 1}, ${item.w} by ${item.h}`
}

function applyGestureDelta(
  kind: GestureKind,
  origin: WidgetLayoutItem,
  dx: number,
  dy: number,
  layout: readonly WidgetLayoutItem[],
  columns: number
): WidgetLayoutItem[] {
  if (kind === "move") {
    return moveWidget(layout, origin.id, origin.x + dx, origin.y + dy, columns)
  }
  let nextW = origin.w
  let nextH = origin.h
  if (kind === "resize-e" || kind === "resize-se") nextW = origin.w + dx
  if (kind === "resize-s" || kind === "resize-se") nextH = origin.h + dy
  return resizeWidget(layout, origin.id, nextW, nextH, columns)
}

function previewFromDelta(
  session: PointerSession,
  clientX: number,
  clientY: number,
  layout: readonly WidgetLayoutItem[],
  columns: number
): GesturePreview {
  const deltaPxX = clientX - session.startClientX
  const deltaPxY = clientY - session.startClientY
  const cellDelta = cellDeltaFromPointer(
    deltaPxX,
    deltaPxY,
    session.metrics
  )
  const nextLayout = applyGestureDelta(
    session.kind,
    session.origin,
    cellDelta.dx,
    cellDelta.dy,
    layout,
    columns
  )
  const draft = layoutById(nextLayout).get(session.id) ?? session.origin
  const snapped = translateFromCellDelta(
    {
      dx: draft.x - session.origin.x,
      dy: draft.y - session.origin.y,
    },
    session.metrics
  )

  if (session.kind === "move") {
    return {
      id: session.id,
      kind: session.kind,
      draft,
      translateX: snapped.x,
      translateY: snapped.y,
      scaleX: 1,
      scaleY: 1,
    }
  }

  const originW = Math.max(session.origin.w * session.metrics.colStride, 1)
  const originH = Math.max(session.origin.h * session.metrics.rowStride, 1)
  const nextW = Math.max(draft.w * session.metrics.colStride, 1)
  const nextH = Math.max(draft.h * session.metrics.rowStride, 1)

  return {
    id: session.id,
    kind: session.kind,
    draft,
    translateX: 0,
    translateY: 0,
    scaleX: nextW / originW,
    scaleY: nextH / originH,
  }
}

function WidgetGrid({
  className,
  layout,
  onLayoutChange,
  renderWidget,
  columns = DEFAULT_COLUMNS,
  editable = true,
  minRowHeight,
  emptyContent,
  style,
  "aria-label": ariaLabel = "Widget grid",
  ...props
}: WidgetGridProps) {
  const rootRef = React.useRef<HTMLDivElement | null>(null)
  const sessionRef = React.useRef<PointerSession | null>(null)
  const previewRef = React.useRef<GesturePreview | null>(null)
  const captureTargetRef = React.useRef<HTMLElement | null>(null)
  const originLayoutRef = React.useRef<WidgetLayoutItem[]>(layout)

  const [liveMessage, setLiveMessage] = React.useState("")
  const [activePointer, setActivePointer] = React.useState(false)
  const [preview, setPreview] = React.useState<GesturePreview | null>(null)
  const [keyboardDraft, setKeyboardDraft] =
    React.useState<KeyboardDraft | null>(null)

  const announce = React.useCallback((message: string) => {
    setLiveMessage(message)
  }, [])

  const resolvedColumns = Math.max(1, Math.trunc(columns) || DEFAULT_COLUMNS)

  const baseLayout = React.useMemo(
    () => normalizeLayout(layout, resolvedColumns),
    [layout, resolvedColumns]
  )

  const displayLayout = keyboardDraft?.draftLayout ?? baseLayout
  const displayById = React.useMemo(
    () => layoutById(displayLayout),
    [displayLayout]
  )

  const updatePreview = React.useCallback((next: GesturePreview | null) => {
    previewRef.current = next
    setPreview(next)
  }, [])

  const endPointerSession = React.useCallback(() => {
    const session = sessionRef.current
    if (!session) return null
    const currentPreview = previewRef.current
    const target = captureTargetRef.current
    if (target?.hasPointerCapture?.(session.pointerId)) {
      target.releasePointerCapture(session.pointerId)
    }
    captureTargetRef.current = null
    sessionRef.current = null
    updatePreview(null)
    setActivePointer(false)
    return { session, preview: currentPreview }
  }, [updatePreview])

  const commitLayout = React.useCallback(
    (next: WidgetLayoutItem[], origin: WidgetLayoutItem[]) => {
      const resolved = normalizeLayout(next, resolvedColumns)
      if (layoutEquals(resolved, normalizeLayout(origin, resolvedColumns))) {
        announce("Layout unchanged")
        return
      }
      onLayoutChange?.(resolved)
      announce("Layout updated")
    },
    [announce, onLayoutChange, resolvedColumns]
  )

  React.useEffect(() => {
    if (!activePointer) return
    const session = sessionRef.current
    if (!session) return

    const onMove = (event: PointerEvent) => {
      if (event.pointerId !== session.pointerId) return
      updatePreview(
        previewFromDelta(
          session,
          event.clientX,
          event.clientY,
          originLayoutRef.current,
          resolvedColumns
        )
      )
    }

    const finish = (event: PointerEvent, cancelled: boolean) => {
      if (event.pointerId !== session.pointerId) return
      const ended = endPointerSession()
      if (!ended) return
      if (
        cancelled ||
        !ended.preview ||
        ended.preview.id !== ended.session.id
      ) {
        announce("Widget gesture cancelled")
        return
      }
      const committed =
        ended.session.kind === "move"
          ? moveWidget(
              originLayoutRef.current,
              ended.session.id,
              ended.preview.draft.x,
              ended.preview.draft.y,
              resolvedColumns
            )
          : resizeWidget(
              originLayoutRef.current,
              ended.session.id,
              ended.preview.draft.w,
              ended.preview.draft.h,
              resolvedColumns
            )
      commitLayout(committed, originLayoutRef.current)
    }

    const onUp = (event: PointerEvent) => finish(event, false)
    const onCancel = (event: PointerEvent) => finish(event, true)
    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key !== "Escape") return
      event.preventDefault()
      const ended = endPointerSession()
      if (!ended) return
      announce("Widget gesture cancelled")
    }

    window.addEventListener("pointermove", onMove)
    window.addEventListener("pointerup", onUp)
    window.addEventListener("pointercancel", onCancel)
    window.addEventListener("keydown", onKeyDown)
    return () => {
      window.removeEventListener("pointermove", onMove)
      window.removeEventListener("pointerup", onUp)
      window.removeEventListener("pointercancel", onCancel)
      window.removeEventListener("keydown", onKeyDown)
    }
  }, [
    activePointer,
    announce,
    commitLayout,
    endPointerSession,
    resolvedColumns,
    updatePreview,
  ])

  const beginPointerGesture = React.useCallback(
    (
      event: React.PointerEvent<HTMLElement>,
      item: WidgetLayoutItem,
      kind: GestureKind
    ) => {
      if (!editable || event.button !== 0) return
      const root = rootRef.current
      if (!root) return
      event.preventDefault()
      event.stopPropagation()

      originLayoutRef.current = baseLayout
      setKeyboardDraft(null)
      const metrics = captureGridMetrics(root, resolvedColumns)
      sessionRef.current = {
        pointerId: event.pointerId,
        kind,
        id: item.id,
        origin: item,
        startClientX: event.clientX,
        startClientY: event.clientY,
        metrics,
      }
      updatePreview({
        id: item.id,
        kind,
        draft: item,
        translateX: 0,
        translateY: 0,
        scaleX: 1,
        scaleY: 1,
      })
      setActivePointer(true)
      announce(
        kind === "move"
          ? `Moving widget at ${formatWidgetCell(item)}`
          : `Resizing widget at ${formatWidgetCell(item)}`
      )
      captureTargetRef.current = event.currentTarget
      event.currentTarget.setPointerCapture?.(event.pointerId)
    },
    [announce, baseLayout, editable, resolvedColumns, updatePreview]
  )

  const onItemPointerDown = React.useCallback(
    (event: React.PointerEvent<HTMLElement>, item: WidgetLayoutItem) => {
      if (!editable) return
      const target = event.target
      if (!(target instanceof Element)) return
      const handle = target.closest(DRAG_HANDLE_SELECTOR)
      if (!handle || !event.currentTarget.contains(handle)) return
      beginPointerGesture(event, item, "move")
    },
    [beginPointerGesture, editable]
  )

  const onHandleKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLElement>, item: WidgetLayoutItem) => {
      if (!editable) return

      if (event.key === "Escape") {
        if (!keyboardDraft || keyboardDraft.id !== item.id) return
        event.preventDefault()
        setKeyboardDraft(null)
        announce("Widget edit cancelled")
        return
      }

      if (event.key === "Enter") {
        if (!keyboardDraft || keyboardDraft.id !== item.id) return
        event.preventDefault()
        const { originLayout, draftLayout } = keyboardDraft
        setKeyboardDraft(null)
        commitLayout(draftLayout, originLayout)
        return
      }

      const isArrow =
        event.key === "ArrowLeft" ||
        event.key === "ArrowRight" ||
        event.key === "ArrowUp" ||
        event.key === "ArrowDown"
      if (!isArrow) return
      event.preventDefault()

      const originLayout = keyboardDraft?.originLayout ?? baseLayout
      const liveLayout = keyboardDraft?.draftLayout ?? baseLayout
      const live = layoutById(liveLayout).get(item.id) ?? item

      let nextLayout: WidgetLayoutItem[]
      if (event.shiftKey) {
        const dw =
          event.key === "ArrowRight" ? 1 : event.key === "ArrowLeft" ? -1 : 0
        const dh =
          event.key === "ArrowDown" ? 1 : event.key === "ArrowUp" ? -1 : 0
        nextLayout = resizeWidget(
          liveLayout,
          item.id,
          live.w + dw,
          live.h + dh,
          resolvedColumns
        )
      } else {
        const dx =
          event.key === "ArrowRight" ? 1 : event.key === "ArrowLeft" ? -1 : 0
        const dy =
          event.key === "ArrowDown" ? 1 : event.key === "ArrowUp" ? -1 : 0
        nextLayout = moveWidget(
          liveLayout,
          item.id,
          live.x + dx,
          live.y + dy,
          resolvedColumns
        )
      }

      setKeyboardDraft({
        id: item.id,
        originLayout,
        draftLayout: nextLayout,
      })
      const nextItem = layoutById(nextLayout).get(item.id) ?? live
      announce(
        `${event.shiftKey ? "Resized" : "Moved"} to ${formatWidgetCell(nextItem)}. Press Enter to commit.`
      )
    },
    [
      announce,
      baseLayout,
      commitLayout,
      editable,
      keyboardDraft,
      resolvedColumns,
    ]
  )

  const isEmpty = displayLayout.length === 0
  const reducedMotion = prefersReducedMotion()

  const rootStyle = {
    ...style,
    "--df-widget-grid-columns": String(resolvedColumns),
    ...(minRowHeight
      ? { "--df-widget-grid-row-height": minRowHeight }
      : {}),
  } as React.CSSProperties

  return (
    <div
      {...props}
      ref={rootRef}
      data-df="widget-grid"
      data-editable={editable ? "true" : "false"}
      data-empty={isEmpty ? "true" : undefined}
      data-dragging={activePointer ? "true" : undefined}
      className={cn("df-widget-grid", className)}
      style={rootStyle}
      role="grid"
      aria-label={ariaLabel}
      aria-rowcount={
        displayLayout.reduce((max, item) => Math.max(max, item.y + item.h), 0) ||
        1
      }
      aria-colcount={resolvedColumns}
    >
      {isEmpty ? (
        <div
          className="df-widget-grid-empty"
          data-df="widget-grid-empty"
          role="status"
        >
          {emptyContent ?? "No widgets"}
        </div>
      ) : (
        displayLayout.map((item) => {
          const activePreview =
            preview?.id === item.id ? preview : null
          const draftItem =
            activePreview?.draft ?? displayById.get(item.id) ?? item
          const ghostItem = activePreview?.draft

          return (
            <React.Fragment key={item.id}>
              <div
                className="df-widget-grid-item"
                data-df="widget-grid-item"
                data-widget-id={item.id}
                data-dragging={activePreview ? "true" : undefined}
                role="gridcell"
                aria-colindex={item.x + 1}
                aria-rowindex={item.y + 1}
                style={{
                  gridColumn: `${item.x + 1} / span ${item.w}`,
                  gridRow: `${item.y + 1} / span ${item.h}`,
                  transform: activePreview
                    ? `translate(${activePreview.translateX}px, ${activePreview.translateY}px) scale(${activePreview.scaleX}, ${activePreview.scaleY})`
                    : undefined,
                  transformOrigin: "top left",
                  transition:
                    activePreview || reducedMotion
                      ? "none"
                      : "transform var(--df-duration-quick) var(--df-ease-standard)",
                }}
                {...(editable
                  ? {
                      onPointerDown: (
                        event: React.PointerEvent<HTMLDivElement>
                      ) => onItemPointerDown(event, item),
                      onKeyDown: (
                        event: React.KeyboardEvent<HTMLDivElement>
                      ) => {
                        const target = event.target
                        if (!(target instanceof Element)) return
                        const onHandle =
                          target.closest(DRAG_HANDLE_SELECTOR) != null ||
                          target.closest(
                            '[data-df="widget-grid-keyboard-handle"]'
                          ) != null
                        if (!onHandle) return
                        onHandleKeyDown(event, item)
                      },
                    }
                  : {})}
              >
                <div className="df-widget-grid-item-body">
                  {renderWidget(item.id)}
                </div>
                {editable ? (
                  <>
                    <button
                      type="button"
                      className="df-widget-grid-keyboard-handle"
                      data-df="widget-grid-keyboard-handle"
                      aria-label={`Move or resize widget at ${formatWidgetCell(draftItem)}`}
                    />
                    <span
                      className="df-widget-grid-resize df-widget-grid-resize-e"
                      data-df="widget-grid-resize"
                      data-edge="e"
                      onPointerDown={(event) =>
                        beginPointerGesture(event, item, "resize-e")
                      }
                    />
                    <span
                      className="df-widget-grid-resize df-widget-grid-resize-s"
                      data-df="widget-grid-resize"
                      data-edge="s"
                      onPointerDown={(event) =>
                        beginPointerGesture(event, item, "resize-s")
                      }
                    />
                    <span
                      className="df-widget-grid-resize df-widget-grid-resize-se"
                      data-df="widget-grid-resize"
                      data-edge="se"
                      onPointerDown={(event) =>
                        beginPointerGesture(event, item, "resize-se")
                      }
                    />
                  </>
                ) : null}
              </div>
              {ghostItem ? (
                <div
                  className="df-widget-grid-ghost"
                  data-df="widget-grid-ghost"
                  aria-hidden
                  style={{
                    gridColumn: `${ghostItem.x + 1} / span ${ghostItem.w}`,
                    gridRow: `${ghostItem.y + 1} / span ${ghostItem.h}`,
                  }}
                />
              ) : null}
            </React.Fragment>
          )
        })
      )}

      <div
        className="df-widget-grid-live"
        data-df="widget-grid-live"
        aria-live="polite"
        aria-atomic="true"
      >
        {liveMessage}
      </div>
    </div>
  )
}

export { WidgetGrid }
export type { WidgetLayoutItem }

export type WidgetLayoutItem = {
  id: string
  x: number
  y: number
  w: number
  h: number
  minW?: number
  minH?: number
  maxW?: number
  maxH?: number
}

export type WidgetGridLayout = WidgetLayoutItem[]

export type WidgetGridBounds = {
  columns: number
}

const DEFAULT_COLUMNS = 12

function finiteInt(value: number, fallback: number): number {
  if (!Number.isFinite(value)) return fallback
  return Math.trunc(value)
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value))
}

function sortLayout(layout: readonly WidgetLayoutItem[]): WidgetLayoutItem[] {
  return [...layout].sort(
    (a, b) => a.y - b.y || a.x - b.x || a.id.localeCompare(b.id)
  )
}

function resolveColumns(columns: number | undefined): number {
  const next = finiteInt(columns ?? DEFAULT_COLUMNS, DEFAULT_COLUMNS)
  return Math.max(1, next)
}

/** Clamp a widget into column bounds and min/max size constraints. */
export function clampWidget(
  item: WidgetLayoutItem,
  columns: number = DEFAULT_COLUMNS
): WidgetLayoutItem {
  const cols = resolveColumns(columns)
  const minW = Math.max(1, finiteInt(item.minW ?? 1, 1))
  const minH = Math.max(1, finiteInt(item.minH ?? 1, 1))
  const maxW = Math.max(minW, finiteInt(item.maxW ?? cols, cols))
  const maxHRaw = item.maxH
  const maxH =
    maxHRaw === undefined || !Number.isFinite(maxHRaw)
      ? Number.POSITIVE_INFINITY
      : Math.max(minH, Math.trunc(maxHRaw))

  const w = clamp(finiteInt(item.w, minW), minW, Math.min(maxW, cols))
  const h = clamp(
    finiteInt(item.h, minH),
    minH,
    Number.isFinite(maxH) ? maxH : Number.MAX_SAFE_INTEGER
  )
  const x = clamp(finiteInt(item.x, 0), 0, Math.max(0, cols - w))
  const y = Math.max(0, finiteInt(item.y, 0))

  return {
    ...item,
    x,
    y,
    w,
    h,
    minW,
    minH,
    ...(item.maxW !== undefined ? { maxW } : {}),
    ...(item.maxH !== undefined && Number.isFinite(maxH) ? { maxH } : {}),
  }
}

export function widgetsOverlap(
  a: Pick<WidgetLayoutItem, "x" | "y" | "w" | "h">,
  b: Pick<WidgetLayoutItem, "x" | "y" | "w" | "h">
): boolean {
  return (
    a.x < b.x + b.w &&
    a.x + a.w > b.x &&
    a.y < b.y + b.h &&
    a.y + a.h > b.y
  )
}

function pushClearOfPlaced(
  item: WidgetLayoutItem,
  placed: readonly WidgetLayoutItem[]
): WidgetLayoutItem {
  let next = item
  let guard = 0
  while (guard < 10_000) {
    guard += 1
    let blocker: WidgetLayoutItem | null = null
    for (const other of placed) {
      if (widgetsOverlap(next, other)) {
        if (
          blocker === null ||
          other.y + other.h > blocker.y + blocker.h ||
          (other.y + other.h === blocker.y + blocker.h &&
            other.id.localeCompare(blocker.id) < 0)
        ) {
          blocker = other
        }
      }
    }
    if (blocker === null) return next
    next = { ...next, y: blocker.y + blocker.h }
  }
  return next
}

/**
 * Clamp every widget and resolve overlaps by pushing later items down.
 * Sort order is row, then column, then id.
 */
export function normalizeLayout(
  layout: readonly WidgetLayoutItem[],
  columns: number = DEFAULT_COLUMNS
): WidgetLayoutItem[] {
  const cols = resolveColumns(columns)
  const clamped = sortLayout(layout.map((item) => clampWidget(item, cols)))
  const placed: WidgetLayoutItem[] = []
  for (const item of clamped) {
    placed.push(pushClearOfPlaced(item, placed))
  }
  return sortLayout(placed)
}

/**
 * Remove vertical gaps while preserving left-to-right, top-to-bottom order.
 */
export function compactLayout(
  layout: readonly WidgetLayoutItem[],
  columns: number = DEFAULT_COLUMNS
): WidgetLayoutItem[] {
  const cols = resolveColumns(columns)
  const ordered = sortLayout(layout.map((item) => clampWidget(item, cols)))
  const placed: WidgetLayoutItem[] = []
  for (const item of ordered) {
    placed.push(pushClearOfPlaced({ ...item, y: 0 }, placed))
  }
  return sortLayout(placed)
}

/**
 * Resolve a layout where `priorityId` keeps its clamped seat and others
 * are pushed down when they collide.
 */
export function resolveLayoutKeeping(
  layout: readonly WidgetLayoutItem[],
  priorityId: string,
  columns: number = DEFAULT_COLUMNS
): WidgetLayoutItem[] {
  const cols = resolveColumns(columns)
  const clamped = layout.map((item) => clampWidget(item, cols))
  const priority = clamped.find((item) => item.id === priorityId)
  if (!priority) return normalizeLayout(clamped, cols)

  const others = sortLayout(clamped.filter((item) => item.id !== priorityId))
  const placed: WidgetLayoutItem[] = [priority]
  for (const item of others) {
    placed.push(pushClearOfPlaced(item, placed))
  }
  return sortLayout(placed)
}

/** Move a widget to a cell origin and return a fully resolved layout. */
export function moveWidget(
  layout: readonly WidgetLayoutItem[],
  id: string,
  x: number,
  y: number,
  columns: number = DEFAULT_COLUMNS
): WidgetLayoutItem[] {
  const cols = resolveColumns(columns)
  const current = layout.find((item) => item.id === id)
  if (!current) return normalizeLayout(layout, cols)

  const nextX = finiteInt(x, current.x)
  const nextY = finiteInt(y, current.y)
  if (nextX === current.x && nextY === current.y) {
    return normalizeLayout(layout, cols)
  }

  const next = layout.map((item) =>
    item.id === id ? { ...item, x: nextX, y: nextY } : item
  )
  return resolveLayoutKeeping(next, id, cols)
}

/** Resize a widget and return a fully resolved layout. */
export function resizeWidget(
  layout: readonly WidgetLayoutItem[],
  id: string,
  w: number,
  h: number,
  columns: number = DEFAULT_COLUMNS
): WidgetLayoutItem[] {
  const cols = resolveColumns(columns)
  const current = layout.find((item) => item.id === id)
  if (!current) return normalizeLayout(layout, cols)

  const nextW = finiteInt(w, current.w)
  const nextH = finiteInt(h, current.h)
  if (nextW === current.w && nextH === current.h) {
    return normalizeLayout(layout, cols)
  }

  const next = layout.map((item) =>
    item.id === id ? { ...item, w: nextW, h: nextH } : item
  )
  return resolveLayoutKeeping(next, id, cols)
}

export function layoutById(
  layout: readonly WidgetLayoutItem[]
): Map<string, WidgetLayoutItem> {
  const map = new Map<string, WidgetLayoutItem>()
  for (const item of layout) map.set(item.id, item)
  return map
}

export function layoutEquals(
  a: readonly WidgetLayoutItem[],
  b: readonly WidgetLayoutItem[]
): boolean {
  if (a.length !== b.length) return false
  const bById = layoutById(b)
  for (const item of a) {
    const other = bById.get(item.id)
    if (!other) return false
    if (
      item.x !== other.x ||
      item.y !== other.y ||
      item.w !== other.w ||
      item.h !== other.h
    ) {
      return false
    }
  }
  return true
}

export { DEFAULT_COLUMNS }

export type WidgetGridCellMetrics = {
  /** Distance between consecutive column origins, including gap. */
  colStride: number
  /** Distance between consecutive row origins, including gap. */
  rowStride: number
}

export type WidgetGridCellDelta = {
  dx: number
  dy: number
}

/**
 * Build column and row strides from a grid bounding box captured at drag start.
 */
export function cellMetricsFromGridRect(input: {
  width: number
  columns: number
  rowHeight: number
  gapX: number
  gapY: number
}): WidgetGridCellMetrics {
  const columns = Math.max(1, Math.trunc(input.columns))
  const gapX = Number.isFinite(input.gapX) && input.gapX >= 0 ? input.gapX : 0
  const gapY = Number.isFinite(input.gapY) && input.gapY >= 0 ? input.gapY : 0
  const width = Number.isFinite(input.width) ? Math.max(0, input.width) : 0
  const rowHeight =
    Number.isFinite(input.rowHeight) && input.rowHeight > 0
      ? input.rowHeight
      : 1

  const colTrack =
    columns === 0 ? 0 : Math.max(0, (width - gapX * (columns - 1)) / columns)
  const colStride = colTrack + gapX
  const rowStride = rowHeight + gapY

  return {
    colStride: colStride > 0 ? colStride : 1,
    rowStride: rowStride > 0 ? rowStride : 1,
  }
}

function unitsFromDelta(deltaPx: number, stride: number): number {
  if (!Number.isFinite(deltaPx) || !Number.isFinite(stride) || stride <= 0) {
    return 0
  }
  // Half-cell hysteresis with symmetric midpoint rounding away from zero.
  const ratio = deltaPx / stride
  const sign = ratio < 0 ? -1 : 1
  return sign * Math.round(Math.abs(ratio))
}

/**
 * Map pointer deltas to grid cell deltas using metrics captured at drag start.
 */
export function cellDeltaFromPointer(
  deltaPxX: number,
  deltaPxY: number,
  metrics: WidgetGridCellMetrics
): WidgetGridCellDelta {
  return {
    dx: unitsFromDelta(deltaPxX, metrics.colStride),
    dy: unitsFromDelta(deltaPxY, metrics.rowStride),
  }
}

/** Convert a cell delta back into a pixel translate for the drag layer. */
export function translateFromCellDelta(
  delta: WidgetGridCellDelta,
  metrics: WidgetGridCellMetrics
): { x: number; y: number } {
  return {
    x: delta.dx * metrics.colStride,
    y: delta.dy * metrics.rowStride,
  }
}

import type { WidgetLayoutItem } from "./layout"

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value)
}

function readOptionalPositiveInt(
  value: unknown
): number | undefined {
  if (value === undefined) return undefined
  if (typeof value !== "number" || !Number.isInteger(value) || value < 1) {
    return undefined
  }
  return value
}

function isNonNegativeInt(value: number): boolean {
  return Number.isInteger(value) && value >= 0
}

function isPositiveInt(value: number): boolean {
  return Number.isInteger(value) && value >= 1
}

function parseItem(value: unknown): WidgetLayoutItem | null {
  if (!isPlainObject(value)) return null
  if (typeof value.id !== "string" || value.id.length === 0) return null

  const x = value.x
  const y = value.y
  const w = value.w
  const h = value.h
  if (
    typeof x !== "number" ||
    !Number.isFinite(x) ||
    typeof y !== "number" ||
    !Number.isFinite(y) ||
    typeof w !== "number" ||
    !Number.isFinite(w) ||
    typeof h !== "number" ||
    !Number.isFinite(h)
  ) {
    return null
  }

  if (!isNonNegativeInt(x) || !isNonNegativeInt(y)) return null
  if (!isPositiveInt(w) || !isPositiveInt(h)) return null

  const item: WidgetLayoutItem = {
    id: value.id,
    x,
    y,
    w,
    h,
  }

  if ("minW" in value) {
    const minW = readOptionalPositiveInt(value.minW)
    if (minW === undefined) return null
    item.minW = minW
  }
  if ("minH" in value) {
    const minH = readOptionalPositiveInt(value.minH)
    if (minH === undefined) return null
    item.minH = minH
  }
  if ("maxW" in value) {
    const maxW = readOptionalPositiveInt(value.maxW)
    if (maxW === undefined) return null
    item.maxW = maxW
  }
  if ("maxH" in value) {
    const maxH = readOptionalPositiveInt(value.maxH)
    if (maxH === undefined) return null
    item.maxH = maxH
  }

  return item
}

/** Serialize a layout into a plain JSON-safe array. */
export function serializeLayout(
  layout: readonly WidgetLayoutItem[]
): Array<Record<string, unknown>> {
  return layout.map((item) => {
    const entry: Record<string, unknown> = {
      id: item.id,
      x: item.x,
      y: item.y,
      w: item.w,
      h: item.h,
    }
    if (item.minW !== undefined) entry.minW = item.minW
    if (item.minH !== undefined) entry.minH = item.minH
    if (item.maxW !== undefined) entry.maxW = item.maxW
    if (item.maxH !== undefined) entry.maxH = item.maxH
    return entry
  })
}

/**
 * Parse a persisted layout payload.
 * Returns null when the root value or any entry is malformed.
 */
export function parseLayout(value: unknown): WidgetLayoutItem[] | null {
  if (!Array.isArray(value)) return null
  const items: WidgetLayoutItem[] = []
  const seen = new Set<string>()
  for (const entry of value) {
    const item = parseItem(entry)
    if (item === null) return null
    if (seen.has(item.id)) return null
    seen.add(item.id)
    items.push(item)
  }
  return items
}
